// Register handoff transitions with context transfer rules
const analyzeToSecurityHandoff = new Handoff({
  from: codeAnalyzerAgent,
  to: securityReviewerAgent,
  // Define what state is transferred in the handoff
  transferContext: (context) => ({
    analyzedFiles: context.analyzedFiles,
    focusAreas: context.focusAreas,
  }),
});

const securityToImproverHandoff = new Handoff({
  from: securityReviewerAgent,
  to: codeImproverAgent,
  transferContext: (context) => ({
    vulnerabilities: context.vulnerabilities,
    severity: context.severity,
  }),
});

// Step 2: Create supervisor agent to orchestrate the pipeline
const pipelineSupervisor = new Agent({
  name: "pipeline-supervisor",
  instructions: `You orchestrate a multi-stage code review pipeline. Follow these stages in order:
1. Use the code-analyzer to understand the codebase structure
2. Hand off to security-reviewer for security analysis
3. Finally, use code-improver to generate improvements

Ensure all findings are properly documented in the shared state.`,
  tools: [],
});

// Step 3: Pipeline execution with state management
async function runMultiStagePipeline(sourcePath: string) {
  // Initialize shared state that persists across all agents
  const pipelineState = {
    sourcePath,
    startTime: Date.now(),
    stages: [] as string[],
    findings: {
      structure: null as any,
      security: null as any,
      improvements: [] as any[],
    },
    errors: [] as string[],
  };

  try {
    // Stage 1: Code Analysis
    console.log("Stage 1: Analyzing code structure...");
    const analysisResult = await codeAnalyzerAgent.run(
      `Analyze the structure of the codebase at: ${sourcePath}`,
      { context: pipelineState }
    );
    pipelineState.findings.structure = analysisResult.finalOutput;
    pipelineState.stages.push("analysis-complete");

    // Stage 2: Security Review with handoff
    console.log("Stage 2: Performing security review...");
    const securityHandoff = handoffRegistry.getHandoff(codeAnalyzerAgent, securityReviewerAgent);
    const securityResult = await securityReviewerAgent.run(
      analysisResult.finalOutput,
      { context: securityHandoff?.transferContext(pipelineState) || pipelineState }
    );
    pipelineState.findings.security = securityResult.finalOutput;
    pipelineState.stages.push("security-review-complete");

    // Stage 3: Improvement Generation with handoff
    console.log("Stage 3: Generating improvements...");
    const improverHandoff = handoffRegistry.getHandoff(securityReviewerAgent, codeImproverAgent);
    const improvementResult = await codeImproverAgent.run(
      JSON.stringify(pipelineState.findings),
      { context: improverHandoff?.transferContext(pipelineState) || pipelineState }
    );
    pipelineState.findings.improvements = improvementResult.finalOutput;
    pipelineState.stages.push("improvements-generated");

    return {
      success: true,
      state: pipelineState,
      summary: `Pipeline completed ${pipelineState.stages.length} stages`,
    };
  } catch (error) {
    pipelineState.errors.push(String(error));
    return { success: false, state: pipelineState, error };
  }
}

// Step 4: Run the pipeline
runMultiStagePipeline("/path/to/project")
  .then((result) => {
    console.log("Pipeline Result:", JSON.stringify(result, null, 2));
  })
  .catch(console.error);

