// src/types/user.ts
export interface User {
  id: string;
  email: string;
  name: string;
  createdAt: Date;
  isActive: boolean;
  role: 'admin' | 'user' | 'guest';
}

export interface CreateUserDTO {
  email: string;
  name: string;
  role?: 'admin' | 'user' | 'guest';
}

// src/services/userService.ts (Codex-generated)
import { User, CreateUserDTO } from '../types/user';

// In-memory storage for demonstration (replace with database in production)
const users: Map<string, User> = new Map();

/**
 * Creates a new user with the provided data.
 * Validates email format and ensures unique email addresses.
 */
export function createUser(data: CreateUserDTO): User {
  // Validate email format
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(data.email)) {
    throw new Error('Invalid email format');
  }

  // Check for duplicate email
  const existingUser = Array.from(users.values()).find(
    (user) => user.email.toLowerCase() === data.email.toLowerCase()
  );
  if (existingUser) {
    throw new Error('Email already in use');
  }

  // Create new user
  const newUser: User = {
    id: generateUniqueId(),
    email: data.email.toLowerCase(),
    name: data.name.trim(),
    createdAt: new Date(),
    isActive: true,
    role: data.role || 'user',
  };

  users.set(newUser.id, newUser);
  return newUser;
}

/**
 * Retrieves a user by their unique identifier.
 */
export function getUserById(id: string): User | undefined {
  return users.get(id);
}

/**
 * Retrieves a user by their email address.
 */
export function getUserByEmail(email: string): User | undefined {
  return Array.from(users.values()).find(
    (user) => user.email.toLowerCase() === email.toLowerCase()
  );
}

/**
 * Retrieves all users, optionally filtered by role or active status.
 */
export function getAllUsers(options?: {
  role?: User['role'];
  isActive?: boolean;
}): User[] {
  let filteredUsers = Array.from(users.values());

  if (options?.role) {
    filteredUsers = filteredUsers.filter((user) => user.role === options.role);
  }

  if (options?.isActive !== undefined) {
    filteredUsers = filteredUsers.filter((user) => user.isActive === options.isActive);
  }

  return filteredUsers;
}

/**
 * Updates an existing user's information.
 */
export function updateUser(id: string, updates: Partial<Omit<User, 'id' | 'createdAt'>>): User {
  const user = users.get(id);
  if (!user) {
    throw new Error('User not found');
  }

  const updatedUser: User = {
    ...user,
    ...updates,
    id: user.id, // Prevent id modification
    createdAt: user.createdAt, // Prevent createdAt modification
  };

  users.set(id, updatedUser);
  return updatedUser;
}

/**
 * Deactivates a user account.
 */
export function deactivateUser(id: string): boolean {
  const user = users.get(id);
  if (!user) {
    return false;
  }

  user.isActive = false;
  users.set(id, user);
  return true;
}

// Helper function to generate unique IDs
function generateUniqueId(): string {
  return `${Date.now()}-${Math.random().toString(36).substring(2, 11)}`;
}

// tests/services/userService.test.ts
import {
