        name: 'Test User',
      });

      expect(user.email).toBe('test@example.com');
    });

    it('should trim whitespace from name', () => {
      const user = createUser({
        email: 'test@example.com',
        name: '  Spaced Name  ',
      });

      expect(user.name).toBe('Spaced Name');
    });
  });

  describe('getUserById', () => {
    it('should return user when found', () => {
      const created = createUser({ email: 'find@example.com', name: 'Find Me' });
      const found = getUserById(created.id);

      expect(found).toBeDefined();
      expect(found?.email).toBe('find@example.com');
    });

    it('should return undefined when user not found', () => {
      const found = getUserById('nonexistent-id');

      expect(found).toBeUndefined();
    });
  });

  describe('getUserByEmail', () => {
    it('should find user by email regardless of case', () => {
      createUser({ email: 'search@example.com', name: 'Search User' });
      const found = getUserByEmail('SEARCH@EXAMPLE.COM');

      expect(found).toBeDefined();
      expect(found?.name).toBe('Search User');
    });
  });

  describe('getAllUsers', () => {
    beforeEach(() => {
      createUser({ email: 'admin@test.com', name: 'Admin', role: 'admin' });
      createUser({ email: 'user1@test.com', name: 'User 1', role: 'user' });
      createUser({ email: 'user2@test.com', name: 'User 2', role: 'user' });
      createUser({ email: 'guest@test.com', name: 'Guest', role: 'guest' });
